INSERT INTO scripts (stage, category, target_audience, script_role, sort_order, versions) VALUES (
  'Cold Calling — Telemarketer Script for Ebook Leads (Working Adults)',
  'cold-calling',
  'working-adult',
  'telemarketer',
  0,
  '[{"author": "Telemarketer Script — Ebook / Financial Planning Guide", "content": "## 📞 Cold Calling Script — Facebook Ebook Leads (Working Adults)\n\n### Opening\n\n> Hi, is this _(name)_?\n>\n> I''m **[name]**, from **The Money Bees**. This is a courtesy call to inform you that we have received your interest in getting our **ultimate guide to financial planning** recently.\n>\n> We might have called previously, but you were busy.\n\n---\n\n### Value Proposition\n\n> In order to redeem it, we will need to schedule a meetup with one of our **wealth specialists**.\n>\n> We specialise in helping Singaporeans create a **simple and secure passive income**, and we''ve helped many individuals discover ways to **maximize their CPF and other assets**, ensuring they''re on track to help them **retire decades earlier** than their peers.\n\n---\n\n### Soft Close\n\n> Would you be opposed in exploring how our expert advisors can help you create a **personalized plan**?\n>\n> Can my consultant give you a **callback later at around [XX] timing** to share more about it?\n\n---\n\n### Booking Confirmation\n\n> Okay great, after this call, my manager will send you a **text message**, and all you have to do, is to **reply and acknowledge**, is that okay?\n\n---\n\n### Closing\n\n> Alright great. So just one last thing, this session is just for you to learn more about growing a **simple and secure passive income**, and as long as you **learn something**, then that''s good enough!"}]'::jsonb
);